MERGE INTO CONSULTAS FIN USING (SELECT '002426COMP_FISCAL' INFORME ,TO_CLOB(q'[SELECT BF.COMPANIA, DBF.CUENTA, P.NOMBRE, BF.COMPROBANTE, BF.FECHA, DBF.SALDO_DEBITO, DBF.SALDO_CREDITO, (BF.DEBITO+BF.CREDITO) VALOR, BF.OBSERVACIONES, BF.IMPRESO   FROM BALANCE_FISCAL BF JOIN DETALLE_BALANCE_FISCAL DBF ON
(BF.COMPANIA = DBF.COMPANIA AND BF.COMPROBANTE =  DBF.COMPROBANTE) JOIN PLAN_CONTABLE P ON (P.COMPANIA = DBF.COMPANIA AND P.ANO = DBF.ANO AND P.CODIGO = DBF.CODIGO_CUENTA) WHERE BF.COMPANIA = 's$compania$s' AND BF.ANO = s$ano$s AND BF.COMPROBANTE = 's$comprobante$s' GROUP BY DBF.CUENTA, P.NOMBRE, BF.COMPROBANTE, BF.FECHA, DBF.SALDO_DEBITO, DBF.SALDO_CREDITO, (BF.DEBITO+BF.CREDITO), BF.OBSERVACIONES, BF.IMPRESO,BF.COMPANIA]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);